function genAdd100(){
  const a=10+Math.floor(Math.random()*50), b=10+Math.floor(Math.random()*40);
  if(a+b>100) return genAdd100();
  const s=a+b;
  const w=[s-1,s-10,s+10].map(String);
  return mkQ(`${a} + ${b} = ?`,`${s}`,[`${s}`,...w],'Сложи десятки, потом единицы','Сложение до 100','#2563eb','#dbeafe');
}
function genSub100(){
  const b=10+Math.floor(Math.random()*30), a=b+10+Math.floor(Math.random()*30);
  if(a>100) return genSub100();
  const r=a-b;
  const w=[r-1,r+1,r+10].filter(x=>x>0).map(String);
  return mkQ(`${a} − ${b} = ?`,`${r}`,[`${r}`,...w],'Вычти до круглого числа, потом добавь остаток','Вычитание до 100','#dc2626','#fee2e2');
}
function genMult(){
  const tables=[[2,2,4],[2,3,6],[2,4,8],[2,5,10],[2,6,12],[2,7,14],[2,8,16],[2,9,18],
    [3,3,9],[3,4,12],[3,5,15],[3,6,18],[4,4,16],[4,5,20],[5,5,25],[5,6,30],[5,7,35],[5,8,40],[5,9,45]];
  const [a,b,s]=pick(tables);
  const w=[s-1,s+1,s-a,s+b].filter(x=>x>0&&x!==s).slice(0,3).map(String);
  return mkQ(`${a} × ${b} = ?`,`${s}`,[`${s}`,...w],'Умножение — это повторное сложение','Таблица умножения','#7c3aed','#ede9fe');
}
function genTasks(){
  const n1=5+Math.floor(Math.random()*10), n2=2+Math.floor(Math.random()*8);
  const tasks=[
    {q:`У Вани ${n1} яблок, у Маши на ${n2} больше. Сколько у Маши?`,a:`${n1+n2}`,h:`${n1}+${n2}=${n1+n2}`},
    {q:`В коробке ${n1+n2} карандашей. Взяли ${n2}. Сколько осталось?`,a:`${n1}`,h:`${n1+n2}−${n2}=${n1}`},
    {q:`В классе ${n1} мальчиков и ${n2} девочек. Сколько всего учеников?`,a:`${n1+n2}`,h:`${n1}+${n2}=${n1+n2}`},
    {q:`Купили ${n2} пакета по ${4} апельсина. Сколько всего?`,a:`${n2*4}`,h:`${n2}×4=${n2*4}`},
  ];
  const t=pick(tasks);
  const w=[parseInt(t.a)+1,parseInt(t.a)-1,parseInt(t.a)+n2].filter(x=>x>0&&x!==parseInt(t.a)).map(String);
  return mkQ(t.q,t.a,[t.a,...w],t.h,'Задачи','#16a34a','#dcfce7');
}

